const require_clob = require('../../types/clob.cjs');

//#region src/order-builder/helpers/calculateBuyMarketPrice.ts
/**
* calculateBuyMarketPrice calculates the market price to buy a $$ amount
* @param positions
* @param amountToMatch worth to buy
* @returns
*/
const calculateBuyMarketPrice = (positions, amountToMatch, orderType) => {
	if (!positions.length) throw new Error("no match");
	let sum = 0;
	for (let i = positions.length - 1; i >= 0; i--) {
		const p = positions[i];
		sum += parseFloat(p.size) * parseFloat(p.price);
		if (sum >= amountToMatch) return parseFloat(p.price);
	}
	if (orderType === require_clob.OrderType.FOK) throw new Error("no match");
	return parseFloat(positions[0].price);
};

//#endregion
exports.calculateBuyMarketPrice = calculateBuyMarketPrice;
